<template><div class="panel"><div class="section-head"><div><h2>登录日志</h2><p>记录登录成功与失败事件。</p></div><el-button @click="load">刷新</el-button></div><el-table :data="rows"><el-table-column prop="loginAt" label="时间"/><el-table-column prop="username" label="账号"/><el-table-column prop="ipAddress" label="IP"/><el-table-column prop="userAgent" label="客户端" show-overflow-tooltip/><el-table-column label="结果"><template #default="s"><el-tag :type="s.row.success?'success':'danger'">{{s.row.success?'成功':'失败'}}</el-tag></template></el-table-column><el-table-column prop="message" label="说明"/></el-table><el-pagination v-model:current-page="query.page" :page-size="query.size" :total="total" layout="total, prev, pager, next" @current-change="load"/></div></template><script setup>import{onMounted,reactive,ref}from'vue';import http from'../api/http';const rows=ref([]),total=ref(0);const query=reactive({page:1,size:5});/** 加载登录日志。 */async function load(){const response=await http.get('/system/login-logs',{params:query});rows.value=response.data.items;total.value=response.data.total}onMounted(load)</script>
<!-- 登录日志页面：展示用户登录审计记录。 -->
